            <Linkedin className="w-6 h-6 text-[#0077b5]" />
            Connect LinkedIn
        </h2>
        <p className="text-slate-500 mb-4">
            Bind your account to scrape engagement data or access your profile viewers securely.
        </p>

        <div className={`
