                <option>Per Day</option>
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 transform -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">
            <span className="text-red-500 mr-1">*</span>Total Limit
          </label>
          <p className="text-xs text-slate-400 mb-3">Total contacts for this campaign.</p>
          <div className="flex gap-4">
            <input
              type="text"
              value={isTotalLimitDisabled ? 'N/A' : totalLimit}
              onChange={(e) => !isTotalLimitDisabled && setTotalLimit(e.target.value)}
              disabled={isTotalLimitDisabled}
              placeholder="1000"
              className={`w-1/2 p-3 rounded-xl border outline-none transition-all ${isTotalLimitDisabled ? 'bg-slate-100 text-slate-400 cursor-not-allowed border-slate-200' : 'bg-white border-slate-200 focus:ring-4 focus:ring-blue-50 focus:border-blue-600'}`}
            />
            <div className="relative w-1/2">
              <select disabled={isTotalLimitDisabled} className={`w-full p-3 rounded-xl border bg-white appearance-none outline-none cursor-pointer ${isTotalLimitDisabled ? 'bg-slate-50 border-slate-100 text-slate-400 cursor-not-allowed' : 'border-slate-200 text-slate-700 focus:border-blue-600'}`}>
                <option>In Total</option>
              </select>
               <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 transform -translate-y-1/2 pointer-events-none" />
            </div>
          </div>
          {isTotalLimitDisabled && (
            <p className="text-[11px] text-blue-600 mt-2 leading-relaxed">
              Total limit will be based on the number of users interacting with the posts / visiting your profile.
            </p>
          )}
        </div>
      </div>

      {/* --- EXCLUDE CONTACTS --- */}
      <div className="mb-12 animate-fadeIn">
        <div className="flex items-center justify-between mb-4">
             <h3 className="text-sm font-medium text-slate-500 uppercase tracking-wide">Exclude Contacts</h3>
             <div className="h-px bg-slate-100 flex-1 ml-4"></div>
        </div>

        <div className="border border-slate-200 rounded-xl overflow-hidden">
          <div className="bg-white p-4 flex items-center justify-between cursor-pointer hover:bg-slate-50 transition-colors">
            <div className="flex items-center gap-2">
                <span className="font-medium text-slate-800">Manage Blacklist</span>
                <span className="text-slate-400 text-sm">Exclude specific contacts from your campaign.</span>
            </div>
            <ChevronUp className="w-4 h-4 text-slate-400" />
          </div>

          <div className="p-4 border-t border-slate-100 bg-slate-50/30 flex flex-wrap gap-4">
            <BlacklistOption 
              icon={<FileText className="w-5 h-5 text-orange-500" />}
